#include<bits/stdc++.h>
using namespace std;
struct node{
	int w,s;
}a[50005];
int cmp(node x,node y){
	return x.w+x.s<y.w+y.s;
}
int main(void){
    int n,t=0,maxn=-9999999;
    cin>>n;
    for(int i=0;i<n;i++)cin>>a[i].w>>a[i].s;
    sort(a,a+n,cmp);
    for(int i=0;i<n;i++){
    	maxn=max(maxn,t-a[i].s);
    	t+=a[i].w;
	}
	cout<<maxn;
    return false;
}
